  ('fire-eq-tech-moex-02084', 'fire-eq-tech', 'fire-eq-tech-moex-103-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '火警自動警報設備預備電源及緊急電源（內藏型）性能檢查及判定方法，下列何者錯誤？', '["預備電源之容量超過緊急電源時，得取代緊急電源", "電壓表指示不正常時，充電不足可能為原因之一", "切換裝置，自動切換成緊急電源；常用電源恢復時，可自動切換成常用電源", "充電回路使用抵抗器者，如有發熱現象，即可判定為異常"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "0e3006dbc1e0", "answer_pdf_sha1": "a2ad16ce6025", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "402", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
